//! protocol69-monster-coordinator -- Skymesh cache-miss lazy fill coordinator.
//!
//! Claims certificate-bearing cache work from Skymesh, answers through the
//! configured browser-fleet pool, and posts a hard-gated cache-fill ack.

use distributed_inference::protocol69::{
    build_protocol69_cache_fill_ack, build_protocol69_workflow_leg_ack,
    validate_protocol69_cache_fill_ack, validate_protocol69_workflow_certificate,
    validate_protocol69_workflow_leg_ack, Protocol69CacheFillAck, Protocol69WorkflowCertificate,
    Protocol69WorkflowLeg, Protocol69WorkflowLegAck, WorkflowExecutor, WorkflowWorkKind,
};
use serde::{Deserialize, Serialize};
use std::time::Duration;

const DEFAULT_SKYMESH_URL: &str = "http://127.0.0.1:8788";
const DEFAULT_BROWSER_FLEET_URL: &str = "http://127.0.0.1:8789";
const DEFAULT_AGENT_ID: &str = "monster-coordinator";
const DEFAULT_POLL_MS: u64 = 1_000;

#[derive(Debug, Clone, PartialEq, Eq)]
struct Cli {
    skymesh_url: String,
    browser_fleet_url: String,
    agent_id: String,
    poll_ms: u64,
    once: bool,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct SkymeshClaimRequest {
    agent_id: String,
    skills: Vec<WorkflowWorkKind>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct SkymeshClaim {
    status: String,
    work: Option<SkymeshCacheWork>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct SkymeshCacheWork {
    workflow_id: String,
    dispatch_id: String,
    final_dispatch_id: String,
    leg_id: String,
    cache_key: String,
    tokens: Vec<u32>,
    model: String,
    qspec: String,
    source_node: String,
    browser_fleet_url: Option<String>,
    prompt: Option<String>,
    executor: WorkflowExecutor,
    work_kind: WorkflowWorkKind,
    certificate: Protocol69WorkflowCertificate,
    leg: Protocol69WorkflowLeg,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct SkymeshAck {
    ack_kind: String,
    cache_fill: Protocol69CacheFillAck,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct SkymeshLegAck {
    ack_kind: String,
    leg_ack: Protocol69WorkflowLegAck,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct BrowserFleetLazyAnswer {
    ok: Option<bool>,
    ack_kind: Option<String>,
    theorem_id: Option<String>,
    answer_text: Option<String>,
    provenance: Option<String>,
    certificate: Option<Protocol69WorkflowCertificate>,
    leg_ack: Option<Protocol69WorkflowLegAck>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum CoordinatorStep {
    Idle,
    CompletedLeg { cache_key: String, leg_id: String },
    CompletedFill { cache_key: String },
}

fn parse_cli() -> Result<Cli, String> {
    let mut cli = Cli {
        skymesh_url: DEFAULT_SKYMESH_URL.to_string(),
        browser_fleet_url: DEFAULT_BROWSER_FLEET_URL.to_string(),
        agent_id: DEFAULT_AGENT_ID.to_string(),
        poll_ms: DEFAULT_POLL_MS,
        once: false,
    };

    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--skymesh-url" => {
                cli.skymesh_url = args.next().ok_or("--skymesh-url requires a value")?
            }
            "--browser-fleet-url" => {
                cli.browser_fleet_url = args.next().ok_or("--browser-fleet-url requires a value")?
            }
            "--agent-id" => cli.agent_id = args.next().ok_or("--agent-id requires a value")?,
            "--poll-ms" => {
                cli.poll_ms = args
                    .next()
                    .ok_or("--poll-ms requires a value")?
                    .parse()
                    .map_err(|_| "--poll-ms must be a positive integer".to_string())?;
                if cli.poll_ms == 0 {
                    return Err("--poll-ms must be positive".to_string());
                }
            }
            "--once" => cli.once = true,
            "--help" | "-h" => return Err(usage()),
            other => return Err(format!("unknown arg {other}\n{}", usage())),
        }
    }
    Ok(cli)
}

fn usage() -> String {
    "usage: protocol69-monster-coordinator [--skymesh-url URL] [--browser-fleet-url URL] [--agent-id ID] [--poll-ms N] [--once]".to_string()
}

fn normalize_base_url(url: &str) -> String {
    url.trim_end_matches('/').to_string()
}

fn claim_skymesh_work(agent: &ureq::Agent, cli: &Cli) -> Result<SkymeshClaim, String> {
    let url = format!(
        "{}/protocol69/work/claim",
        normalize_base_url(&cli.skymesh_url)
    );
    let body = SkymeshClaimRequest {
        agent_id: cli.agent_id.clone(),
        skills: vec![
            WorkflowWorkKind::RunInferenceX,
            WorkflowWorkKind::RunInferenceY,
            WorkflowWorkKind::ComputeZ,
            WorkflowWorkKind::ForkjoinMcpInvocation,
        ],
    };
    agent
        .post(&url)
        .set("Content-Type", "application/json")
        .send_json(serde_json::to_value(body).map_err(|error| error.to_string())?)
        .map_err(|error| format!("POST {url} failed: {error}"))?
        .into_json::<SkymeshClaim>()
        .map_err(|error| format!("decode Skymesh claim failed: {error}"))
}

fn answer_with_browser_fleet(
    agent: &ureq::Agent,
    browser_fleet_url: &str,
    work: &SkymeshCacheWork,
) -> Result<(Protocol69WorkflowLegAck, String), String> {
    let url = format!(
        "{}/protocol69/lazy-answer",
        normalize_base_url(browser_fleet_url)
    );
    let request = serde_json::json!({
        "work": work
    });
    let response = agent
        .post(&url)
        .set("Content-Type", "application/json")
        .send_json(request)
        .map_err(|error| format!("POST {url} failed: {error}"))?
        .into_json::<BrowserFleetLazyAnswer>()
        .map_err(|error| format!("decode browser-fleet response failed: {error}"))?;
    if response.ok != Some(true) {
        return Err("browser-fleet lazy answer was not ok".to_string());
    }
    if response.ack_kind.as_deref() != Some("legAck") {
        return Err("browser-fleet lazy answer was not a legAck".to_string());
    }
    let certificate = response
        .certificate
        .as_ref()
        .ok_or_else(|| "browser-fleet lazy answer omitted certificate".to_string())?;
    validate_protocol69_workflow_certificate(certificate)?;
    if certificate != &work.certificate {
        return Err("browser-fleet lazy answer certificate does not match work".to_string());
    }
    let leg_ack = response
        .leg_ack
        .ok_or_else(|| "browser-fleet lazy answer omitted legAck".to_string())?;
    validate_protocol69_workflow_leg_ack(&leg_ack)?;
    if leg_ack.workflow_id != work.workflow_id
        || leg_ack.dispatch_id != work.dispatch_id
        || leg_ack.leg_id != work.leg_id
        || leg_ack.cache_key != work.cache_key
        || leg_ack.executor != work.executor
        || leg_ack.work_kind != work.work_kind
    {
        return Err("browser-fleet legAck does not match claimed work".to_string());
    }
    let answer = response
        .answer_text
        .filter(|text| !text.trim().is_empty())
        .ok_or_else(|| "browser-fleet lazy answer did not include answerText".to_string())?;
    let provenance = response
        .provenance
        .filter(|text| !text.trim().is_empty())
        .unwrap_or_else(|| "cf-browser-fleet:protocol69-lazy-answer".to_string());
    Ok((leg_ack, format!("{provenance}:{answer}")))
}

fn complete_coordinator_leg(work: &SkymeshCacheWork) -> Result<Protocol69WorkflowLegAck, String> {
    let result_hash = format!(
        "coordinator-fold:{}:{}:{}",
        work.workflow_id, work.leg_id, work.cache_key
    );
    build_protocol69_workflow_leg_ack(&work.leg, result_hash, "protocol69-monster-coordinator")
}

fn ack_skymesh_fill(
    agent: &ureq::Agent,
    skymesh_url: &str,
    ack: Protocol69CacheFillAck,
) -> Result<(), String> {
    validate_protocol69_cache_fill_ack(&ack)?;
    let url = format!("{}/protocol69/work/ack", normalize_base_url(skymesh_url));
    let body = SkymeshAck {
        ack_kind: "cacheFill".to_string(),
        cache_fill: ack,
    };
    agent
        .post(&url)
        .set("Content-Type", "application/json")
        .send_json(serde_json::to_value(body).map_err(|error| error.to_string())?)
        .map_err(|error| format!("POST {url} failed: {error}"))?;
    Ok(())
}

fn ack_skymesh_leg(
    agent: &ureq::Agent,
    skymesh_url: &str,
    ack: Protocol69WorkflowLegAck,
) -> Result<(), String> {
    validate_protocol69_workflow_leg_ack(&ack)?;
    let url = format!("{}/protocol69/work/ack", normalize_base_url(skymesh_url));
    let body = SkymeshLegAck {
        ack_kind: "legAck".to_string(),
        leg_ack: ack,
    };
    agent
        .post(&url)
        .set("Content-Type", "application/json")
        .send_json(serde_json::to_value(body).map_err(|error| error.to_string())?)
        .map_err(|error| format!("POST {url} failed: {error}"))?;
    Ok(())
}

fn run_once(http: &ureq::Agent, cli: &Cli) -> Result<CoordinatorStep, String> {
    let claim = claim_skymesh_work(http, cli)?;
    if claim.status == "idle" {
        return Ok(CoordinatorStep::Idle);
    }
    if claim.status != "claimed" {
        return Err(format!("unexpected Skymesh claim status {}", claim.status));
    }
    let work = claim
        .work
        .ok_or_else(|| "claimed Skymesh response omitted work".to_string())?;
    let leg_ack = match work.executor {
        WorkflowExecutor::BrowserFleet => {
            let browser_fleet_url = work
                .browser_fleet_url
                .as_deref()
                .filter(|url| !url.trim().is_empty())
                .unwrap_or(&cli.browser_fleet_url);
            answer_with_browser_fleet(http, browser_fleet_url, &work)?.0
        }
        WorkflowExecutor::CoordinatorSelf => complete_coordinator_leg(&work)?,
        other => {
            return Err(format!(
                "monster coordinator cannot execute {:?}/{:?}",
                other, work.work_kind
            ));
        }
    };
    ack_skymesh_leg(http, &cli.skymesh_url, leg_ack.clone())?;
    if work.executor == WorkflowExecutor::CoordinatorSelf
        && work.work_kind == WorkflowWorkKind::ComputeZ
    {
        let answer = format!(
            "protocol69 workflow {} filled after {}",
            work.cache_key, leg_ack.result_hash
        );
        let answer_tokens = answer.bytes().map(u32::from).collect::<Vec<_>>();
        let ack = build_protocol69_cache_fill_ack(
            work.workflow_id,
            work.final_dispatch_id,
            work.cache_key.clone(),
            answer_tokens,
            answer,
            "protocol69-monster-coordinator:workflow-fold",
        )?;
        ack_skymesh_fill(http, &cli.skymesh_url, ack)?;
        return Ok(CoordinatorStep::CompletedFill {
            cache_key: work.cache_key,
        });
    }
    Ok(CoordinatorStep::CompletedLeg {
        cache_key: work.cache_key,
        leg_id: work.leg_id,
    })
}

fn run(cli: Cli) -> Result<(), String> {
    let http = ureq::AgentBuilder::new()
        .timeout_connect(Duration::from_secs(2))
        .timeout_read(Duration::from_secs(30))
        .timeout_write(Duration::from_secs(10))
        .build();

    loop {
        match run_once(&http, &cli)? {
            CoordinatorStep::Idle => {
                if cli.once {
                    println!("protocol69-monster-coordinator idle");
                    return Ok(());
                }
                std::thread::sleep(Duration::from_millis(cli.poll_ms));
            }
            CoordinatorStep::CompletedLeg { cache_key, leg_id } => {
                println!("protocol69-monster-coordinator completed leg {leg_id} for {cache_key}");
                if cli.once {
                    return Ok(());
                }
            }
            CoordinatorStep::CompletedFill { cache_key } => {
                println!("protocol69-monster-coordinator completed fill {cache_key}");
                if cli.once {
                    return Ok(());
                }
            }
        }
    }
}

fn main() {
    match parse_cli().and_then(run) {
        Ok(()) => {}
        Err(error) => {
            eprintln!("{error}");
            std::process::exit(2);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use distributed_inference::protocol69::{
        build_protocol69_workflow_certificate, build_protocol69_workflow_leg,
        build_protocol69_workflow_leg_ack,
    };
    use std::net::TcpListener;
    use std::sync::{Arc, Mutex};
    use std::thread;
    use tiny_http::{Header, Response, Server};

    fn start_server<F>(handler: F) -> String
    where
        F: Fn(String, String) -> String + Send + Sync + 'static,
    {
        let listener = TcpListener::bind("127.0.0.1:0").expect("bind");
        let addr = listener.local_addr().expect("addr");
        let server = Server::from_listener(listener, None).expect("server");
        let handler = Arc::new(handler);
        thread::spawn(move || {
            for mut request in server.incoming_requests().take(4) {
                let mut body = String::new();
                let _ = request.as_reader().read_to_string(&mut body);
                let response_body = handler(request.url().to_string(), body);
                let _ = request.respond(Response::from_string(response_body).with_header(
                    Header::from_bytes("Content-Type", "application/json").expect("header"),
                ));
            }
        });
        format!("http://{addr}")
    }

    fn work_json() -> serde_json::Value {
        let leg = build_protocol69_workflow_leg(
            "workflow-cache-key-49af",
            "browser-inference-x",
            "49af207da814",
            vec![],
            WorkflowExecutor::BrowserFleet,
            WorkflowWorkKind::RunInferenceX,
            Some("args:siphash:browser".to_string()),
        )
        .expect("leg");
        serde_json::json!({
            "status": "claimed",
            "work": {
                "workflowId": "workflow-cache-key-49af",
                "dispatchId": "workflow-cache-key-49af:browser-inference-x",
                "finalDispatchId": "workflow-cache-key-49af:cache-fill",
                "legId": "browser-inference-x",
                "cacheKey": "49af207da814",
                "tokens": [1, 2, 3],
                "model": "distilgpt2",
                "qspec": "skymesh-query/v2",
                "sourceNode": "cf-cache-skymesh-global",
                "prompt": "say cached",
                "executor": "browserFleet",
                "workKind": "runInferenceX",
                "certificate": build_protocol69_workflow_certificate(),
                "leg": leg
            }
        })
    }

    fn fold_work_json() -> serde_json::Value {
        let leg = build_protocol69_workflow_leg(
            "workflow-cache-key-49af",
            "fold-z",
            "49af207da814",
            vec![
                "browser-inference-x".to_string(),
                "browser-inference-y".to_string(),
            ],
            WorkflowExecutor::CoordinatorSelf,
            WorkflowWorkKind::ComputeZ,
            None,
        )
        .expect("leg");
        serde_json::json!({
            "status": "claimed",
            "work": {
                "workflowId": "workflow-cache-key-49af",
                "dispatchId": "workflow-cache-key-49af:fold-z",
                "finalDispatchId": "workflow-cache-key-49af:cache-fill",
                "legId": "fold-z",
                "cacheKey": "49af207da814",
                "tokens": [1, 2, 3],
                "model": "distilgpt2",
                "qspec": "skymesh-query/v2",
                "sourceNode": "cf-cache-skymesh-global",
                "executor": "coordinatorSelf",
                "workKind": "computeZ",
                "certificate": build_protocol69_workflow_certificate(),
                "leg": leg
            }
        })
    }

    #[test]
    fn coordinator_claims_browser_fleet_and_acks_leg() {
        let ack_seen = Arc::new(Mutex::new(false));
        let ack_seen_server = Arc::clone(&ack_seen);
        let skymesh = start_server(move |url, body| {
            if url == "/protocol69/work/claim" {
                assert!(body.contains("monster-coordinator"));
                return work_json().to_string();
            }
            if url == "/protocol69/work/ack" {
                assert!(body.contains("\"ackKind\":\"legAck\""));
                *ack_seen_server.lock().expect("lock") = true;
                return serde_json::json!({"status":"accepted"}).to_string();
            }
            serde_json::json!({"status":"idle"}).to_string()
        });
        let fleet = start_server(|url, _body| {
            assert_eq!(url, "/protocol69/lazy-answer");
            let leg = build_protocol69_workflow_leg(
                "workflow-cache-key-49af",
                "browser-inference-x",
                "49af207da814",
                vec![],
                WorkflowExecutor::BrowserFleet,
                WorkflowWorkKind::RunInferenceX,
                Some("args:siphash:browser".to_string()),
            )
            .expect("leg");
            let leg_ack = build_protocol69_workflow_leg_ack(
                &leg,
                "browser-fleet:siphash:ok",
                "cf-browser-fleet:protocol69-lazy-answer",
            )
            .expect("leg ack");
            serde_json::json!({
                "ok": true,
                "ackKind": "legAck",
                "answerText": "cached by browser fleet",
                "provenance": "cf-browser-fleet:protocol69-lazy-answer",
                "certificate": build_protocol69_workflow_certificate(),
                "legAck": leg_ack
            })
            .to_string()
        });
        let cli = Cli {
            skymesh_url: skymesh,
            browser_fleet_url: fleet,
            agent_id: "monster-coordinator".to_string(),
            poll_ms: 1,
            once: true,
        };
        let http = ureq::AgentBuilder::new().build();

        let step = run_once(&http, &cli).expect("run once");

        assert_eq!(
            step,
            CoordinatorStep::CompletedLeg {
                cache_key: "49af207da814".to_string(),
                leg_id: "browser-inference-x".to_string()
            }
        );
        assert!(*ack_seen.lock().expect("lock"));
    }

    #[test]
    fn coordinator_self_fold_posts_final_cache_fill() {
        let ack_bodies = Arc::new(Mutex::new(Vec::<String>::new()));
        let ack_bodies_server = Arc::clone(&ack_bodies);
        let skymesh = start_server(move |url, body| {
            if url == "/protocol69/work/claim" {
                return fold_work_json().to_string();
            }
            if url == "/protocol69/work/ack" {
                ack_bodies_server.lock().expect("lock").push(body);
                return serde_json::json!({"status":"accepted"}).to_string();
            }
            serde_json::json!({"status":"idle"}).to_string()
        });
        let cli = Cli {
            skymesh_url: skymesh,
            browser_fleet_url: "http://127.0.0.1:1".to_string(),
            agent_id: "monster-coordinator".to_string(),
            poll_ms: 1,
            once: true,
        };
        let http = ureq::AgentBuilder::new().build();

        let step = run_once(&http, &cli).expect("run once");

        assert_eq!(
            step,
            CoordinatorStep::CompletedFill {
                cache_key: "49af207da814".to_string()
            }
        );
        let bodies = ack_bodies.lock().expect("lock");
        assert_eq!(bodies.len(), 2);
        assert!(bodies[0].contains("\"ackKind\":\"legAck\""));
        assert!(bodies[1].contains("\"ackKind\":\"cacheFill\""));
    }

    #[test]
    fn coordinator_rejects_uncertified_browser_fleet_answer() {
        let skymesh = start_server(move |url, body| {
            if url == "/protocol69/work/claim" {
                assert!(body.contains("monster-coordinator"));
                return work_json().to_string();
            }
            if url == "/protocol69/work/ack" {
                panic!("forged browser-fleet answer must not be acked");
            }
            serde_json::json!({"status":"idle"}).to_string()
        });
        let fleet = start_server(|url, _body| {
            assert_eq!(url, "/protocol69/lazy-answer");
            serde_json::json!({
                "ok": true,
                "ackKind": "legAck",
                "theoremId": "forged",
                "answerText": "uncertified"
            })
            .to_string()
        });
        let cli = Cli {
            skymesh_url: skymesh,
            browser_fleet_url: fleet,
            agent_id: "monster-coordinator".to_string(),
            poll_ms: 1,
            once: true,
        };
        let http = ureq::AgentBuilder::new().build();

        let error = run_once(&http, &cli).expect_err("forged answer rejected");

        assert!(error.contains("omitted certificate"));
    }
}
